import React, { useEffect, useState } from "react";
import "./MedicinePage.css";

const FALLBACK = [
  { name: "Dolo 650mg Strip Of 15 Tablets", price: 24.1, discount: 25 },
  { name: "Leemol 650mg Strip Of 15 Tablets", price: 16.7, discount: 47 },
  { name: "Dolopar 650mg Strip Of 15 Tablets", price: 23.74, discount: 25 },
];

const API_BASE = (process.env.REACT_APP_API_BASE || "http://localhost:5000/api").replace(/\/+$/, "");

export default function MedicinePage() {
  const [medicines, setMedicines] = useState(FALLBACK);
  const [query, setQuery] = useState("");
  const [filtered, setFiltered] = useState([]);
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${API_BASE}/public/medicines`);
        const data = await res.json();
        if (Array.isArray(data) && data.length) {
          // Expecting {name, price, discount}
          setMedicines(
            data.map((m) => ({
              name: m.name,
              price: Number(m.price) || 0,
              discount: Number(m.discount) || 0,
            }))
          );
        }
      } catch (_) {
        // keep fallback silently
      }
    })();
  }, []);

  const runFilter = (val) => {
    const v = val.toLowerCase();
    if (!v) return setFiltered([]);
    setFiltered(medicines.filter((m) => m.name.toLowerCase().includes(v)));
  };

  const handleSearch = (e) => {
    e.preventDefault();
    runFilter(query);
  };

  const handleSelect = (item) => {
    setSelected(item);
    setFiltered([]);
    setQuery(item.name);
  };

  return (
    <section className="medicine-page">
      <div className="hero-section">
        <h2>
          Get <span className="highlight">Medicines Fast</span> with Superfast
          Delivery in your city
        </h2>

        <div className="features">
          <div className="feature-card">💰 <span>Cash on Delivery</span></div>
          <div className="feature-card">🚚 <span>Express Delivery</span></div>
          <div className="feature-card">🔁 <span>Easy Returns</span></div>
        </div>
      </div>

      <div className="search-container">
        <form onSubmit={handleSearch} className="search-box">
          <input
            type="text"
            placeholder="Search for Medicines..."
            value={query}
            onChange={(e) => {
              const val = e.target.value;
              setQuery(val);
              runFilter(val);
            }}
          />
          <button type="submit">Search</button>
        </form>

        {filtered.length > 0 && (
          <ul className="suggestions">
            {filtered.map((item, i) => (
              <li key={i} onClick={() => handleSelect(item)}>
                <div className="suggestion-item">
                  <span className="suggestion-name">{item.name}</span>
                </div>
              </li>
            ))}
            <li className="view-all">View All Results</li>
          </ul>
        )}

        <div className="offers">
          <div className="offer-box app-offer">
            <h4>APP ONLY OFFER</h4>
            <p>
              Get <strong>25% OFF</strong> on order above Rs 1000
            </p>
            <p>on medicine & healthcare</p>
            <button className="install-btn">Install App 📱</button>
          </div>
          <div className="offer-box web-offer">
            <h4>WEBSITE OFFER</h4>
            <p>
              Get <strong>23% OFF</strong> on medicine orders
            </p>
            <button className="coupon-btn">CODE: 23NUFIT</button>
          </div>
        </div>
      </div>

      {selected && (
        <div className="results">
          <h3>
            Showing all results for <strong>{selected.name}</strong>
          </h3>

          <div className="result-list">
            {medicines.map((m, i) => (
              <div key={i} className="result-card">
                <div className="med-info">
                  <h4>{m.name}</h4>
                  <p>15 Tablet(s) in Strip</p>
                  <p>
                    <strong>₹{m.price}</strong>{" "}
                    <span className="off">{m.discount}% OFF</span>
                  </p>
                </div>
                <button className="add-btn">Add To Cart</button>
              </div>
            ))}
          </div>

          <div className="prescription">
            <h4>🧾 What is a valid prescription?</h4>
            <ul>
              <li>Doctor Details</li>
              <li>Date of Prescription</li>
              <li>Patient Details</li>
              <li>Dosage Details</li>
            </ul>
          </div>
        </div>
      )}
    </section>
  );
}
